   163→    filter_factories.push_back({std::move(filter_config_provider), disabled_by_default});
   164→    return absl::OkStatus();
   165→  }
   166→
   167→  absl::Status
   168→  processDynamicFilterConfig(const std::string& name,
   169→                             const envoy::config::core::v3::ExtensionConfigSource& config_discovery,
   170→                             FilterFactoriesList& filter_factories,
   171→                             const std::string& filter_chain_type,
   172→                             bool last_filter_in_current_config, bool disabled_by_default) {
   173→    ENVOY_LOG(debug, "      dynamic filter name: {}", name);
   174→    if (config_discovery.apply_default_config_without_warming() &&
   175→        !config_discovery.has_default_config()) {
   176→      return absl::InvalidArgumentError(fmt::format(
   177→          "Error: filter config {} applied without warming but has no default config.", name));
   178→    }
   179→    for (const auto& type_url : config_discovery.type_urls()) {
   180→      auto factory_type_url = TypeUtil::typeUrlToDescriptorFullName(type_url);
   181→      auto* factory = Registry::FactoryRegistry<NeutralNamedHttpFilterFactory>::getFactoryByType(
   182→          factory_type_url);
   183→      if (factory == nullptr) {
   184→        return absl::InvalidArgumentError(
   185→            fmt::format("Error: no factory found for a required type URL {}.", factory_type_url));
   186→      }
   187→    }
   188→
   189→    auto filter_config_provider = filter_config_provider_manager_.createDynamicFilterConfigProvider(
   190→        config_discovery, name, server_context_, factory_context_, cluster_manager_,
   191→        last_filter_in_current_config, filter_chain_type, nullptr);
   192→    filter_factories.push_back({std::move(filter_config_provider), disabled_by_default});
   193→    return absl::OkStatus();
   194→  }
   195→
   196→  FilterConfigProviderManager& filter_config_provider_manager_;
   197→  Server::Configuration::ServerFactoryContext& server_context_;
   198→  Upstream::ClusterManager& cluster_manager_;
   199→  FilterCtx& factory_context_;
   200→  const std::string& stats_prefix_;
   201→};
